        }
      ]
    }
  }
}

sections.body:
To learn more about these queries, see [query](embedded-documents-tutorial-queries).

Nested Array

To learn more about this query, see [query](embedded-documents-tutorial-queries).

| Pipeline Stage | Query                                                                                                                                                                                                                                                                                                                  |
| -------------- | ---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------- |
| $search        | \{ "index": "embedded-documents-tutorial", "embeddedDocument": \{ "path": "teachers", "operator": \{ "compound": \{ "must": \[\{ "text": \{ "path": "teachers.first", "query": "John" } }], "should":\[\{ "text": \{ "path": "teachers.last", "query": "Smith" } }] } } }, "highlight": \{ "path": "teachers.last" } } |
| $project       | \{ "\_id": 1, "teachers": 1, "score": \{ $meta: "searchScore" }, "highlights": \{ "$meta": "searchHighlights" } }If you enabled Auto Preview, MongoDB Compass displays the following documents next to the $project pipeline stage:                                                                                    |

```shell
[
  {
    _id: 1,
    teachers: [
      {
        first: 'Jane',
        last: 'Earwhacker',
        classes: [
          { subject: 'art', grade: '9th' },
          { subject: 'science', grade: '12th' }
        ]
      },
      {
        first: 'John',
        last: 'Smith',
        classes: [
          { subject: 'math', grade: '12th' },
          { subject: 'art', grade: '10th' }
        ]
      }
    ],
    score: 0.7830756902694702,
    highlights: [
      {
        score: 1.4921371936798096,
        path: 'teachers.last',
        texts: [ { value: 'Smith', type: 'hit' } ]
      }
    ]
  },
  {
    _id: 2,
    teachers: [
      {
        first: 'Jane',
        last: 'Smith',
        classes: [
          { subject: 'science', grade: '9th' },
          { subject: 'math', grade: '12th' }
        ]
      },
      {
        first: 'John',
        last: 'Redman',
        classes: [ { subject: 'art', grade: '12th' } ]
      }
    ],
    score: 0.468008816242218,
    highlights: [
      {
        score: 1.4702850580215454,
        path: 'teachers.last',
        texts: [ { value: 'Smith', type: 'hit' } ]
      }
    ]
  }
]
```

The two documents in the results contain teachers with the first name
`John`. The document with `_id: 1` ranks higher because it
contains a teacher with the first name `John` who also has the last
name `Smith`.

Nested Array Within Object

To learn more about this query, see [query](embedded-documents-tutorial-queries).

| Pipeline Stage | Query                                                                                                                                                                                              |
| -------------- | -------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------- |
| $search        | \{ "index": "embedded-documents-tutorial", embeddedDocument: \{ path: "clubs.sports", operator: \{ queryString: \{ defaultPath: "clubs.sports.club\_name", query: "dodgeball OR frisbee", } } } }  |
| $project       | \{ "\_id": 1, "name": 1, "clubs.sports": 1, "score": \{ $meta: "searchScore" } }If you enabled Auto Preview, MongoDB Compass displays the following documents next to the $project pipeline stage: |

```shell
[
  {
    _id: 2,
    name: 'Lincoln High',
    clubs: {
      sports: [
        {
          club_name: 'dodgeball',
          description: 'provides students an opportunity to play dodgeball by throwing balls to eliminate the members of the opposing team while avoiding being hit themselves.'
        },
        {
          club_name: 'martial arts',
          description: 'provides students an opportunity to learn self-defense or combat that utilize physical skill and coordination without weapons.'
        }
      ]
    },
    score: 0.633669912815094
  },
  {
    _id: 1,
    name: 'Evergreen High',
    clubs: {
      sports: [
        {
          club_name: 'archery',
          description: 'provides students an opportunity to practice and hone the skill of using a bow to shoot arrows in a fun and safe environment.'
        },
        {
          club_name: 'ultimate frisbee',
          description: 'provides students an opportunity to play frisbee and learn the basics of holding the disc and complete passes.'
        }
      ]
    },
    score: 0.481589138507843
  }
]
```

The two documents in the results show schools that offer clubs where
students could play `dodgeball` or `frisbee`.

