    'first': 'John', 
    'last': 'Smith', 
    'classes': [{'subject': 'math', 'grade': '12th'}, {'subject': 'art', 'grade': '10th'}]
  }], 
  'score': 0.7830756902694702, 
  'highlights': [{
    'score': 1.4921371936798096, 
    'path': 'teachers.last', 
    'texts': [{'value': 'Smith', 'type': 'hit'}]
